function debounce(func, wait) {
    let timeoutId;
    return function() {
        const context = this;
        const args = arguments;
        clearTimeout(timeoutId);
        timeoutId = setTimeout(() => {
            func.apply(context, args);
        }, wait);
    };
}

// Example usage:
function sayHello() {
    console.log("Hello!");
}

const debouncedHello = debounce(sayHello, 1000);
debouncedHello(); // This will not log "Hello!" immediately
setTimeout(() => debouncedHello(), 1500); // This will log "Hello!" after 1 second
```
